const Skills = () => {
  const skillCategories = [
    {
      title: "Frontend Development",
      skills: [
        { name: "React", level: 90 },
        { name: "JavaScript", level: 85 },
        { name: "TypeScript", level: 80 },
        { name: "HTML/CSS", level: 95 },
        { name: "Tailwind CSS", level: 85 },
        { name: "Vue.js", level: 70 }
      ]
    },
    {
      title: "Backend Development", 
      skills: [
        { name: "Node.js", level: 85 },
        { name: "Express.js", level: 80 },
        { name: "Python", level: 75 },
        { name: "Java", level: 70 },
        { name: "REST APIs", level: 85 },
        { name: "GraphQL", level: 65 }
      ]
    },
    {
      title: "Database & Tools",
      skills: [
        { name: "MongoDB", level: 80 },
        { name: "PostgreSQL", level: 75 },
        { name: "MySQL", level: 70 },
        { name: "Git", level: 90 },
        { name: "Docker", level: 65 },
        { name: "AWS", level: 60 }
      ]
    }
  ];

  const techStack = [
    "React", "Node.js", "JavaScript", "TypeScript", "Python", "Java",
    "MongoDB", "PostgreSQL", "Express.js", "CSS", "Git", "Docker",
    "AWS", "Vue.js", "REST API", "GraphQL"
  ];

  return (
    <section id="skills" className="skills">
      <div className="container">
        <h2 className="section-title">Skills & Technologies</h2>

        <div className="skills-grid lg-grid-cols-3">
          {skillCategories.map((category, categoryIndex) => (
            <div key={categoryIndex} className="skill-category">
              <h3 className="skill-category-title">{category.title}</h3>

              <div className="skill-list">
                {category.skills.map((skill, skillIndex) => (
                  <div key={skillIndex} className="skill-item">
                    <div className="skill-header">
                      <span className="skill-name">{skill.name}</span>
                      <span className="skill-percentage">{skill.level}%</span>
                    </div>
                    <div className="skill-bar">
                      <div className="skill-progress" style={{ width: `${skill.level}%` }}></div>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          ))}
        </div>

        <div className="tech-stack-section">
          <h3 className="tech-stack-title">Technologies I Work With</h3>
          <div className="tech-stack-grid">
            {techStack.map((tech, index) => (
              <span key={index} className="tech-tag">{tech}</span>
            ))}
          </div>
        </div>

        <div className="learning-section">
          <h3 className="learning-title">Currently Learning</h3>
          <div className="learning-grid">
            {["Machine Learning", "DevOps", "Kubernetes", "Microservices"].map((item, index) => (
              <span key={index} className="learning-tag">{item}</span>
            ))}
          </div>
        </div>
      </div>
    </section>
  );
};

export default Skills;
